from flask import Flask, request, jsonify
from pymongo import MongoClient
from pymongo.errors import PyMongoError
import os

app = Flask(__name__)

MONGO_URI = os.getenv("MONGO_URI", "mongodb://localhost:27017")
MONGO_DB = os.getenv("MONGO_DB", "testdb")
MONGO_COLLECTION = os.getenv("MONGO_COLLECTION", "documents")

client = MongoClient(MONGO_URI)
db = client[MONGO_DB]
collection = db[MONGO_COLLECTION]

@app.route("/health", methods=["GET"])
def health():
    return jsonify({"status": "ok"})

@app.route("/filter", methods=["POST"])
def filter_documents():
    data = request.get_json(silent=True) or {}
    where_expression = data.get("where")

    if not isinstance(where_expression, str) or not where_expression.strip():
        return jsonify({"error": "Missing or invalid 'where' JavaScript expression"}), 400

    limit = data.get("limit", 100)
    try:
        limit = max(1, min(int(limit), 1000))
    except (TypeError, ValueError):
        return jsonify({"error": "Invalid 'limit' value"}), 400

    projection = data.get("projection")
    if projection is not None and not isinstance(projection, dict):
        return jsonify({"error": "Invalid 'projection' value"}), 400

    try:
        cursor = collection.find({"$where": where_expression}, projection).limit(limit)
        results = []
        for doc in cursor:
            doc["_id"] = str(doc["_id"])
            results.append(doc)
        return jsonify({"count": len(results), "results": results})
    except PyMongoError as e:
        return jsonify({"error": "MongoDB query failed", "details": str(e)}), 500

if __name__ == "__main__":
    host = os.getenv("HOST", "0.0.0.0")
